column.value:
{
  "pageDescription": "Sample Creation & Full Metadata Capture",
  "purpose": "Create the analytical sample as the primary entity and register it for bioanalytical or pharmaceutical analysis",
  "usedBy": ["Reception staff", "Analysts"],
  "dataPoints": {
    "sampleIdentity": {
      "sampleIdentifier": {"type": "text", "label": "Sample Identifier", "description": "Retained from originating lab or newly assigned", "required": true},
      "barcodeQR": {"type": "text", "label": "Barcode / QR code", "required": false},
      "sampleSource": {"type": "choice", "label": "Sample Source", "options": ["Medical Laboratory (processed biological sample)", "Researcher", "External client (outsourced analysis)"], "required": true}
    },
    "sampleCategory": {
      "category": {"type": "choice", "label": "Sample Category", "options": ["Bioanalytical", "Pharmaceutical analysis (physicochemical / R&D)"], "required": true}
    },
    "sampleType": {
      "type": {"type": "choice", "label": "Sample Type", "options": ["API", "Tablet", "Capsule", "Suspension", "Injection", "Cream / ointment", "Processed biological sample (plasma, serum, urine)", "Other"], "required": true}
    },
    "sampleContext": {
      "requestingUnit": {"type": "text", "label": "Requesting unit / researcher / client", "required": true},
      "requestedTests": {"type": "multiSelect", "label": "Requested tests", "options": ["Assay", "Dissolution", "Disintegration", "Friability", "Hardness", "Identity test", "Bioanalytical quantification"], "required": true},
      "studyProjectId": {"type": "text", "label": "Study / project ID", "required": false}
    },
    "storageHandling": {
      "storageCondition": {"type": "text", "label": "Storage condition prior to testing", "required": false},
      "receivedDateTime": {"type": "dateTime", "label": "Received date & time", "required": true},
      "receivedBy": {"type": "text", "label": "Received by (name / initials)", "required": true}
    }
  },
  "systemActions": ["Sample record created", "Label generated", "Sample status: Created - Pending Test Assignment"],
  "nextPage": "Test Assignment & Preparation"
}

{
  "pageDescription": "Test Assignment & Preparation",
  "purpose": "Assign responsibility and select analytical methods per sample",
  "usedBy": ["Lab supervisor", "Section head"],
  "dataPoints": {
    "personnelAssignment": {
      "assignedRole": {"type": "choice", "label": "Assigned role", "options": ["Chemical Analyst", "Pharmacist", "Researcher"], "required": true},
      "assignedAnalystName": {"type": "text", "label": "Assigned analyst name", "required": true},
      "assignmentDate": {"type": "date", "label": "Assignment date", "required": true}
    },
    "methodSelection": {
      "analyticalMethodology": {"type": "multiSelect", "label": "Analytical methodology", "options": ["HPLC", "UV-Vis", "LC-MS/MS", "Dissolution (USP I / USP II)", "Hardness test", "Friability test", "Disintegration test", "Identity test"], "required": true}
    }
  },
  "systemActions": ["Worklist created", "Sample status: Assigned - Ready for Analysis"],
  "bulkOperations": {
    "enabled": true,
    "applyToSelected": ["assignedRole", "assignedAnalystName", "assignmentDate", "analyticalMethodology"]
  },
  "nextPage": "Analysis / Test Execution"
}

{
  "pageDescription": "Analysis / Test Execution",
  "purpose": "Perform analytical testing while preserving data integrity",
  "usedBy": ["Analysts"],
  "dataPoints": {
    "testExecution": {
      "testStartDateTime": {"type": "dateTime", "label": "Test start date & time", "required": true},
      "instrumentUsed": {"type": "text", "label": "Instrument used", "required": true},
      "methodReference": {"type": "text", "label": "Method reference / SOP", "required": true},
      "analystPerforming": {"type": "text", "label": "Analyst performing test", "required": true}
    },
    "chromatographicSpectroscopic": {
      "runId": {"type": "text", "label": "Run ID", "conditionalOn": "methodType == chromatographic", "required": false},
      "systemSuitabilityStatus": {"type": "choice", "label": "System suitability status", "options": ["Pass", "Fail"], "conditionalOn": "methodType == chromatographic", "required": false},
      "calibrationStatus": {"type": "choice", "label": "Calibration status", "options": ["Valid", "Expired", "Not Required"], "required": false},
      "rawDataFileRef": {"type": "text", "label": "Raw data file reference", "required": false}
    },
    "dissolution": {
      "apparatusType": {"type": "choice", "label": "Apparatus type", "options": ["USP I (Basket)", "USP II (Paddle)"], "conditionalOn": "testType == dissolution", "required": false},
      "rpm": {"type": "number", "label": "RPM", "required": false},
      "medium": {"type": "text", "label": "Medium", "required": false},
      "timePoints": {"type": "text", "label": "Time points", "required": false}
    },
    "physicalTests": {
      "individualValues": {"type": "text", "label": "Individual values", "required": false},
      "average": {"type": "number", "label": "Average", "required": false},
      "acceptanceDecision": {"type": "choice", "label": "Acceptance decision", "options": ["Pass", "Fail"], "required": false}
    }
  },
  "systemActions": ["Raw data attached to sample", "Sample status: Analysis Completed - Pending Review"],
  "nextPage": "Result Review, Reporting & Release"
}

{
  "pageDescription": "Result Review, Reporting & Release",
  "purpose": "Validate and release analytical results",
  "usedBy": ["Senior analyst", "Supervisor"],
  "dataPoints": {
    "reviewValidation": {
      "reviewedBy": {"type": "text", "label": "Reviewed by", "required": true},
      "reviewDate": {"type": "date", "label": "Review date", "required": true},
      "complianceWithSpec": {"type": "choice", "label": "Compliance with specification", "options": ["Pass", "Fail"], "required": true},
      "comments": {"type": "text", "label": "Comments", "required": false}
    },
    "reporting": {
      "reportGenerated": {"type": "boolean", "label": "Analytical Result Report generated", "required": true},
      "reportVersion": {"type": "text", "label": "Report version", "required": false},
      "releasedTo": {"type": "multiSelect", "label": "Released to", "options": ["Requesting unit", "Researcher", "Client"], "required": true}
    }
  },
  "systemActions": ["Results locked after approval", "Audit trail finalized", "Sample status: Results Released"],
  "nextPage": "Post-Test Sample & Data Handling"
}

{
  "pageDescription": "Post-Test Sample & Data Handling",
  "purpose": "Manage retention, biorepository transfer, and long-term traceability",
  "usedBy": ["Store manager", "Data manager"],
  "dataPoints": {
    "sampleRetention": {
      "retentionRequired": {"type": "choice", "label": "Retention required", "options": ["Yes", "No"], "required": true},
      "retentionQuantity": {"type": "text", "label": "Retention quantity", "conditionalOn": "retentionRequired == Yes", "required": false},
      "retentionDuration": {"type": "choice", "label": "Retention duration", "options": ["Stability study", "Legal hold", "Protocol-defined"], "conditionalOn": "retentionRequired == Yes", "required": false}
    },
    "biorepositoryTransfer": {
      "transferRequired": {"type": "choice", "label": "Transfer to biorepository", "options": ["Yes", "No"], "required": true},
      "transferDate": {"type": "date", "label": "Transfer date", "conditionalOn": "transferRequired == Yes", "required": false},
      "receivingLaboratory": {"type": "text", "label": "Receiving laboratory", "conditionalOn": "transferRequired == Yes", "required": false},
      "storageCondition": {"type": "text", "label": "Storage condition", "conditionalOn": "transferRequired == Yes", "required": false}
    },
    "dataHandling": {
      "rawDataArchived": {"type": "boolean", "label": "Raw data archived", "required": true},
      "finalReportsArchived": {"type": "boolean", "label": "Final reports archived", "required": true},
      "retentionPeriodLogged": {"type": "boolean", "label": "Retention period logged", "required": true}
    }
  },
  "systemActions": ["Sample lifecycle marked Completed", "Records preserved for compliance"],
  "nextPage": null
}
